(window.webpackJsonp=window.webpackJsonp||[]).push([[735],{701:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">arr</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">d</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxJumps = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">arr, d</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> dp=<span class=\\"hljs-built_in\\">Array</span>(arr.length).fill(<span class=\\"hljs-literal\\">null</span>)\\n  <span class=\\"hljs-keyword\\">let</span> memo=[]\\n  \\n  <span class=\\"hljs-keyword\\">let</span> max=<span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;arr.length;i++){\\n    max=<span class=\\"hljs-built_in\\">Math</span>.max(max,resolve(i))\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> max\\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">resolve</span>(<span class=\\"hljs-params\\">idx</span>)</span>{\\n    <span class=\\"hljs-comment\\">// if(idx===arr.length)return 0</span>\\n    <span class=\\"hljs-comment\\">// console.log(idx)</span>\\n    <span class=\\"hljs-keyword\\">if</span>(memo[idx]!=<span class=\\"hljs-literal\\">null</span>)<span class=\\"hljs-keyword\\">return</span> memo[idx]\\n    <span class=\\"hljs-keyword\\">let</span> leftMax=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> rightMax=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=idx<span class=\\"hljs-number\\">-1</span>;i&gt;=idx-d;i--){\\n      <span class=\\"hljs-keyword\\">if</span>(i&lt;<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">break</span>\\n      <span class=\\"hljs-keyword\\">if</span>(arr[i]&gt;=arr[idx])<span class=\\"hljs-keyword\\">break</span>\\n      leftMax=<span class=\\"hljs-built_in\\">Math</span>.max(leftMax,resolve(i))\\n    }\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=idx+<span class=\\"hljs-number\\">1</span>;i&lt;=idx+d;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(i&gt;=arr.length)<span class=\\"hljs-keyword\\">break</span>\\n      <span class=\\"hljs-keyword\\">if</span>(arr[i]&gt;=arr[idx])<span class=\\"hljs-keyword\\">break</span>\\n      rightMax=<span class=\\"hljs-built_in\\">Math</span>.max(rightMax,resolve(i))\\n    }\\n    memo[idx]=<span class=\\"hljs-built_in\\">Math</span>.max(leftMax,rightMax)+<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">return</span> memo[idx]\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"jump-game-v","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4&nbsp;<code>arr</code> \u548c\u4e00\u4e2a\u6574\u6570&nbsp;<code>d</code> \u3002\u6bcf\u4e00\u6b65\u4f60\u53ef\u4ee5\u4ece\u4e0b\u6807&nbsp;<code>i</code>&nbsp;\u8df3\u5230\uff1a</p>\\n\\n<ul>\\n\\t<li><code>i + x</code>&nbsp;\uff0c\u5176\u4e2d&nbsp;<code>i + x &lt; arr.length</code>&nbsp;\u4e14&nbsp;<code>0 &lt; x &lt;= d</code>&nbsp;\u3002</li>\\n\\t<li><code>i - x</code>&nbsp;\uff0c\u5176\u4e2d&nbsp;<code>i - x &gt;= 0</code>&nbsp;\u4e14&nbsp;<code>0 &lt; x &lt;= d</code>&nbsp;\u3002</li>\\n</ul>\\n\\n<p>\u9664\u6b64\u4ee5\u5916\uff0c\u4f60\u4ece\u4e0b\u6807&nbsp;<code>i</code> \u8df3\u5230\u4e0b\u6807 <code>j</code>&nbsp;\u9700\u8981\u6ee1\u8db3\uff1a<code>arr[i] &gt; arr[j]</code>&nbsp;\u4e14 <code>arr[i] &gt; arr[k]</code>&nbsp;\uff0c\u5176\u4e2d\u4e0b\u6807&nbsp;<code>k</code>&nbsp;\u662f\u6240\u6709 <code>i</code>&nbsp;\u5230 <code>j</code>&nbsp;\u4e4b\u95f4\u7684\u6570\u5b57\uff08\u66f4\u6b63\u5f0f\u7684\uff0c<code>min(i, j) &lt; k &lt; max(i, j)</code>\uff09\u3002</p>\\n\\n<p>\u4f60\u53ef\u4ee5\u9009\u62e9\u6570\u7ec4\u7684\u4efb\u610f\u4e0b\u6807\u5f00\u59cb\u8df3\u8dc3\u3002\u8bf7\u4f60\u8fd4\u56de\u4f60 <strong>\u6700\u591a</strong>&nbsp;\u53ef\u4ee5\u8bbf\u95ee\u591a\u5c11\u4e2a\u4e0b\u6807\u3002</p>\\n\\n<p>\u8bf7\u6ce8\u610f\uff0c\u4efb\u4f55\u65f6\u523b\u4f60\u90fd\u4e0d\u80fd\u8df3\u5230\u6570\u7ec4\u7684\u5916\u9762\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/02/02/meta-chart.jpeg\\" style=\\"height: 419px; width: 633px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [6,4,14,6,8,13,9,7,10,6,12], d = 2\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n<strong>\u89e3\u91ca\uff1a</strong>\u4f60\u53ef\u4ee5\u4ece\u4e0b\u6807 10 \u51fa\u53d1\uff0c\u7136\u540e\u5982\u4e0a\u56fe\u4f9d\u6b21\u7ecf\u8fc7 10 --&gt; 8 --&gt; 6 --&gt; 7 \u3002\\n\u6ce8\u610f\uff0c\u5982\u679c\u4f60\u4ece\u4e0b\u6807 6 \u5f00\u59cb\uff0c\u4f60\u53ea\u80fd\u8df3\u5230\u4e0b\u6807 7 \u5904\u3002\u4f60\u4e0d\u80fd\u8df3\u5230\u4e0b\u6807 5 \u5904\u56e0\u4e3a 13 &gt; 9 \u3002\u4f60\u4e5f\u4e0d\u80fd\u8df3\u5230\u4e0b\u6807 4 \u5904\uff0c\u56e0\u4e3a\u4e0b\u6807 5 \u5728\u4e0b\u6807 4 \u548c 6 \u4e4b\u95f4\u4e14 13 &gt; 9 \u3002\\n\u7c7b\u4f3c\u7684\uff0c\u4f60\u4e0d\u80fd\u4ece\u4e0b\u6807 3 \u5904\u8df3\u5230\u4e0b\u6807 2 \u6216\u8005\u4e0b\u6807 1 \u5904\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [3,3,3,3,3], d = 3\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\u4f60\u53ef\u4ee5\u4ece\u4efb\u610f\u4e0b\u6807\u5904\u5f00\u59cb\u4e14\u4f60\u6c38\u8fdc\u65e0\u6cd5\u8df3\u5230\u4efb\u4f55\u5176\u4ed6\u5750\u6807\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [7,6,5,4,3,2,1], d = 1\\n<strong>\u8f93\u51fa\uff1a</strong>7\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ece\u4e0b\u6807 0 \u5904\u5f00\u59cb\uff0c\u4f60\u53ef\u4ee5\u6309\u7167\u6570\u503c\u4ece\u5927\u5230\u5c0f\uff0c\u8bbf\u95ee\u6240\u6709\u7684\u4e0b\u6807\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [7,1,7,1,7,1], d = 2\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [66], d = 1\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= arr.length &lt;= 1000</code></li>\\n\\t<li><code>1 &lt;= arr[i] &lt;= 10^5</code></li>\\n\\t<li><code>1 &lt;= d &lt;= arr.length</code></li>\\n</ul>\\n","title":"1340. \u8df3\u8dc3\u6e38\u620f V","relatedTags":["\u52a8\u6001\u89c4\u5212"],"difficult":"Hard","lang":["javascript"],"uniqueID":"1340"}')}}]);